22	entity axi_mm_reader is
23	    generic (
24	        TimeoutCkCycles_g   : natural   := 10_000_000;
25	        MaxRegCount_g       : natural    := 1024;
26	        MinBuffers_g        : natural   := 4;
27	        AxiAddrWidth_g      : natural   := 32;
28	        RamBehavior_g       : string    := "RBW"    -- "RBW" = read-before-write, "WBR" = write-before-read
29	    );
30	    port (
31	        -- Control Signals
32	        Clk             : in    std_logic;
33	        Rst             : in    std_logic;
34	
35	        -- Start readout
36	        Trig            : in    std_logic := '0';
37	
38	        -- Readout done
39	        DoneIrq         : out   std_logic;
40	
41	        -- General Configuration
42	        RegCount        : std_logic_vector(log2ceil(MaxRegCount_g)-1 downto 0);
43	        Enable          : std_logic;
44	
45	        -- Register Configuration RAM
46	        RegCfg_Idx      : in    std_logic_vector(log2ceil(MaxRegCount_g)-1 downto 0);
47	        RegCfg_WrReg    : in    std_logic_vector(AxiAddrWidth_g-1 downto 0);
48	        RegCfg_RdReg    : out   std_logic_vector(AxiAddrWidth_g-1 downto 0);
49	        RegCfg_Wr       : in    std_logic;
50	
51	        -- AXI Master Interface
52	        AxiM_CmdRd_Addr     : out   std_logic_vector(AxiAddrWidth_g-1 downto 0);
53	        AxiM_CmdRd_Vld      : out   std_logic;
54	        AxiM_CmdRd_Rdy      : in    std_logic;
55	        AxiM_RdDat_Data     : in    std_logic_vector(31 downto 0);
56	        AxiM_RdDat_Vld      : in    std_logic;
57	        AxiM_RdDat_Rdy      : out   std_logic;
58	
59	        -- AXI-S output data
60	        AxiS_Vld            : out   std_logic;
61	        AxiS_Rdy            : in    std_logic;
62	        AxiS_Last           : out   std_logic;
63	        AxiS_Data           : out   std_logic_vector(31 downto 0);
64	        AxiS_Level          : out   std_logic_vector(31 downto 0)
65	    );
66	end entity;
