69	-- Architecture Declaration
70	------------------------------------------------------------------------------
71	architecture rtl of axi_mm_reader is
72	
73	    -- *** Types ***
74	    type Fsm_t is (Idle_s, ReadAddr_s, SetCmd_s, ApplyCmd_s, WaitDone_s);
75	
76	    -- *** Two Process Method ***
77	    type two_process_r is record
78	        TimeoutCnt      : natural range 0 to TimeoutCkCycles_g-1;
79	        Start           : std_logic;
80	        Fsm             : Fsm_t;
81	        RamAddr         : std_logic_vector(RegCfg_Idx'range);
82	        AxiM_CmdRd_Addr : std_logic_vector(AxiM_CmdRd_Addr'range);
83	        AxiM_CmdRd_Vld  : std_logic;
84	        RegCount        : integer range 0 to MaxRegCount_g;
85	        DoneCnt         : integer range 0 to MaxRegCount_g;
86	        DoneIrq         : std_logic;
87	    end record;
88	    signal r, r_next : two_process_r;
89	
90	    -- *** Component Connections ***
91	    signal RamRegAddr   : std_logic_vector(AxiAddrWidth_g-1 downto 0);
92	    signal Fifo_Rdy     : std_logic;
93		signal Last			: std_logic;
94	
95	begin
96	
97	    --------------------------------------------------------------------------
98	    -- Combinatorial Proccess
99	    --------------------------------------------------------------------------
100	    p_comb : process(r, Trig, RamRegAddr, AxiM_CmdRd_Rdy, Enable, RegCount, AxiM_RdDat_Data, AxiM_RdDat_Vld, Fifo_Rdy)
101	        variable v : two_process_r;
102	    begin
103	        -- *** hold variables stable ***
104	        v := r;
105	
106	        -- *** Trigger ***
107	        v.Start := '0';
108	        if Trig = '1' or r.TimeoutCnt = TimeoutCkCycles_g-1 then
109	            if Enable = '1' then
110	                v.TimeoutCnt := 0;
111	                v.Start := '1';
112	            end if;
113	        else
114	            v.TimeoutCnt := r.TimeoutCnt + 1;
115	        end if;
116	
117	        -- *** FSM ***
118	        v.DoneIrq := '0';
119	        case r.Fsm is
120	            when Idle_s =>
121	                if r.Start = '1' then
122	                    v.Fsm := ReadAddr_s;
123	                end if;
124	                v.RamAddr   := (others => '0');
125	                v.RegCount  := to_integer(unsigned(RegCount));
126	
127	
128	            when ReadAddr_s =>
129	                -- Check if all registers are done
130	                if unsigned(r.RamAddr) = r.RegCount then
131	                    v.Fsm := WaitDone_s;
132	                else
133	                    v.Fsm := SetCmd_s;
134	                end if;
135	                v.RamAddr   := std_logic_vector(unsigned(r.RamAddr) + 1);
136	
137	            when SetCmd_s =>
138	                v.AxiM_CmdRd_Addr   := RamRegAddr;
139	                v.AxiM_CmdRd_Vld    := '1';
140	                v.Fsm               := ApplyCmd_s;
141	
142	            when ApplyCmd_s =>
143	                if AxiM_CmdRd_Rdy = '1' then
144	                    v.AxiM_CmdRd_Vld    := '0';
145						v.Fsm   := ReadAddr_s;
146	                end if;               
147	
148	            when WaitDone_s =>
149	                if r.DoneCnt = r.RegCount then
150	                    v.Fsm       := Idle_s;
151	                    v.DoneIrq   := '1';
152	                end if;
153	
154	            when others => null;
155	        end case;
156	        if Enable = '0' then
157	            v.Fsm := Idle_s;
158				v.TimeoutCnt := 0;
159	        end if;
160	
161	        -- *** Done Handling ***
162	        if r.Fsm = Idle_s and r.Start = '1' then
163	            v.DoneCnt := 0;
164	        elsif (AxiM_RdDat_Vld = '1') and (Fifo_Rdy = '1') then
165	            v.DoneCnt := r.DoneCnt + 1;
166	        end if;
167	
168	        -- *** Detect last word (combinatorial) ***
169	        Last <= '0';
170	        if r.DoneCnt = r.RegCount-1 then
171	            Last <= '1';
172	        end if;
173	
174	        -- *** assign signal ***
175	        r_next <= v;
176	    end process;
177	
178	    --------------------------------------------------------------------------
179	    -- Outputs
180	    --------------------------------------------------------------------------
181	    DoneIrq <= r.DoneIrq;
182	    AxiM_RdDat_Rdy <= Fifo_Rdy;
183		AxiM_CmdRd_Addr <= r.AxiM_CmdRd_Addr;
184		AxiM_CmdRd_Vld <= r.AxiM_CmdRd_Vld;
185		
186	
187	    --------------------------------------------------------------------------
188	    -- Sequential Proccess
189	    --------------------------------------------------------------------------
190	    p_seq : process(Clk)
191	    begin
192	        if rising_edge(Clk) then
193	            r <= r_next;
194	            if Rst = '1' then
195	                r.TimeoutCnt        <= 0;
196	                r.Start             <= '0';
197	                r.Fsm               <= Idle_s;
198	                r.AxiM_CmdRd_Vld    <= '0';
199	            end if;
200	        end if;
201	    end process;
202	
203	    --------------------------------------------------------------------------
204	    -- Component Instantiations
205	    --------------------------------------------------------------------------
206	    i_ram : entity work.psi_common_tdp_ram
207	        generic map (
208	            Depth_g     => MaxRegCount_g,
209	            Width_g     => AxiAddrWidth_g,
210	            Behavior_g  => RamBehavior_g
211	        )
212	        port map (
213	            ClkA        => Clk,
214	            AddrA       => RegCfg_Idx,
215	            WrA         => RegCfg_Wr,
216	            DinA        => RegCfg_WrReg,
217	            DoutA       => RegCfg_RdReg,
218	            ClkB        => Clk,
219	            AddrB       => r.RamAddr,
220	            WrB         => '0',
221	            DinB        => (others => '0'),
222	            DoutB       => RamRegAddr
223	        );
224	
225	    AxiS_Level(31 downto log2ceil(MaxRegCount_g*MinBuffers_g)+1) <= (others => '0');
226	    i_rdfifo : entity work.psi_common_sync_fifo
227	        generic map (
228	            Width_g         => 32+1,
229	            Depth_g         => MaxRegCount_g*MinBuffers_g,
230	            AlmFullOn_g     => false,
231	            AlmEmptyOn_g    => false,
232	            RamStyle_g      => "auto",
233	            RamBehavior_g   => RamBehavior_g
234	        )
235	        port map (
236	            Clk                     => Clk,
237	            Rst                     => Rst,
238	            InData(31 downto 0)     => AxiM_RdDat_Data,
239	            InData(32)              => Last,
240	            InVld                   => AxiM_RdDat_Vld,
241	            InRdy                   => Fifo_Rdy,
242	            OutData(31 downto 0)    => AxiS_Data,
243	            OutData(32)             => AxiS_Last,
244	            OutVld                  => AxiS_Vld,
245	            OutRdy                  => AxiS_Rdy,
246	            OutLevel                => AxiS_Level(log2ceil(MaxRegCount_g*MinBuffers_g) downto 0)
247	        );
248	
249	
250	
251	end;
